/**
 * Employee Form Component - Add/Edit Employee
 * Updated to match database schema (DateOfBirth and HireDate are required, no Address field)
 */

import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { toast } from 'react-toastify';
import { FaSave, FaTimes, FaSync, FaUser } from 'react-icons/fa';
import { employeeAPI, syncAPI } from '../services/api';

function EmployeeForm({ onSuccess }) {
  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = Boolean(id);

  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [departments, setDepartments] = useState([]);
  const [positions, setPositions] = useState([]);
  const [syncAfterSave, setSyncAfterSave] = useState(true);

  const [formData, setFormData] = useState({
    FullName: '',
    DateOfBirth: '',
    Gender: '',
    PhoneNumber: '',
    Email: '',
    HireDate: '',
    Status: 'Active',
    DepartmentID: '',
    PositionID: '',
  });

  const [errors, setErrors] = useState({});

  // Fetch data on mount
  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [deptRes, posRes] = await Promise.all([
          employeeAPI.getDepartments(),
          employeeAPI.getPositions(),
        ]);
        setDepartments(deptRes.data);
        setPositions(posRes.data);

        if (isEditMode) {
          const empRes = await employeeAPI.getById(id);
          const emp = empRes.data;
          setFormData({
            FullName: emp.FullName || '',
            DateOfBirth: emp.DateOfBirth || '',
            Gender: emp.Gender || '',
            PhoneNumber: emp.PhoneNumber || '',
            Email: emp.Email || '',
            HireDate: emp.HireDate || '',
            Status: emp.Status || 'Active',
            DepartmentID: emp.DepartmentID || '',
            PositionID: emp.PositionID || '',
          });
        }
      } catch (error) {
        toast.error('Failed to load data');
        console.error(error);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [id, isEditMode]);

  // Handle input change
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: null }));
    }
  };

  // Validate form
  const validateForm = () => {
    const newErrors = {};

    // Full name is required
    if (!formData.FullName.trim()) {
      newErrors.FullName = 'Full name is required';
    }

    // Date of birth is required
    if (!formData.DateOfBirth) {
      newErrors.DateOfBirth = 'Date of birth is required';
    }

    // Hire date is required
    if (!formData.HireDate) {
      newErrors.HireDate = 'Hire date is required';
    }

    // Email validation (optional but must be valid if provided)
    if (formData.Email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.Email)) {
      newErrors.Email = 'Invalid email format';
    }

    // Phone validation (optional but must be valid if provided)
    if (formData.PhoneNumber && formData.PhoneNumber.length < 10) {
      newErrors.PhoneNumber = 'Phone number must be at least 10 digits';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Handle submit
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) {
      toast.error('Please fix the errors in the form');
      return;
    }

    setSaving(true);
    try {
      const submitData = {
        ...formData,
        DepartmentID: formData.DepartmentID ? parseInt(formData.DepartmentID) : null,
        PositionID: formData.PositionID ? parseInt(formData.PositionID) : null,
      };

      let savedEmployee;
      if (isEditMode) {
        const response = await employeeAPI.update(id, submitData);
        savedEmployee = response.data;
        toast.success('Employee updated successfully');
      } else {
        const response = await employeeAPI.create(submitData);
        savedEmployee = response.data;
        toast.success('Employee created successfully');
      }

      if (syncAfterSave && savedEmployee) {
        try {
          await syncAPI.syncEmployees([savedEmployee.EmployeeID]);
          toast.success('Employee synced to payroll');
        } catch (syncError) {
          toast.warning('Saved but sync failed');
        }
      }

      if (onSuccess) onSuccess();
      navigate('/employees');
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Failed to save');
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="card">
        <div className="card-body">
          <div className="loading">
            <div className="spinner"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="card">
      <div className="card-header">
        <h2>
          <FaUser style={{ marginRight: '10px' }} />
          {isEditMode ? 'Edit Employee' : 'Add New Employee'}
        </h2>
      </div>

      <div className="card-body">
        <form onSubmit={handleSubmit}>
          {/* Row 1: Full Name & Email */}
          <div className="form-row">
            <div className="form-group">
              <label className="form-label">
                Full Name <span style={{ color: '#e53e3e' }}>*</span>
              </label>
              <input
                type="text"
                name="FullName"
                className={`form-control ${errors.FullName ? 'error' : ''}`}
                value={formData.FullName}
                onChange={handleChange}
                placeholder="Enter full name"
              />
              {errors.FullName && <span className="error-text">{errors.FullName}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">Email</label>
              <input
                type="email"
                name="Email"
                className={`form-control ${errors.Email ? 'error' : ''}`}
                value={formData.Email}
                onChange={handleChange}
                placeholder="Enter email"
              />
              {errors.Email && <span className="error-text">{errors.Email}</span>}
            </div>
          </div>

          {/* Row 2: Date of Birth & Hire Date */}
          <div className="form-row">
            <div className="form-group">
              <label className="form-label">
                Date of Birth <span style={{ color: '#e53e3e' }}>*</span>
              </label>
              <input
                type="date"
                name="DateOfBirth"
                className={`form-control ${errors.DateOfBirth ? 'error' : ''}`}
                value={formData.DateOfBirth}
                onChange={handleChange}
              />
              {errors.DateOfBirth && <span className="error-text">{errors.DateOfBirth}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">
                Hire Date <span style={{ color: '#e53e3e' }}>*</span>
              </label>
              <input
                type="date"
                name="HireDate"
                className={`form-control ${errors.HireDate ? 'error' : ''}`}
                value={formData.HireDate}
                onChange={handleChange}
              />
              {errors.HireDate && <span className="error-text">{errors.HireDate}</span>}
            </div>
          </div>

          {/* Row 3: Phone Number & Gender */}
          <div className="form-row">
            <div className="form-group">
              <label className="form-label">Phone Number</label>
              <input
                type="text"
                name="PhoneNumber"
                className={`form-control ${errors.PhoneNumber ? 'error' : ''}`}
                value={formData.PhoneNumber}
                onChange={handleChange}
                placeholder="Enter phone number"
                maxLength={15}
              />
              {errors.PhoneNumber && <span className="error-text">{errors.PhoneNumber}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">Gender</label>
              <select
                name="Gender"
                className="form-control"
                value={formData.Gender}
                onChange={handleChange}
              >
                <option value="">Select Gender</option>
                <option value="Male">Male</option>
                <option value="Female">Female</option>
                <option value="Other">Other</option>
              </select>
            </div>
          </div>

          {/* Row 4: Department & Position */}
          <div className="form-row">
            <div className="form-group">
              <label className="form-label">Department</label>
              <select
                name="DepartmentID"
                className="form-control"
                value={formData.DepartmentID}
                onChange={handleChange}
              >
                <option value="">Select Department</option>
                {departments.map((dept) => (
                  <option key={dept.DepartmentID} value={dept.DepartmentID}>
                    {dept.DepartmentName}
                  </option>
                ))}
              </select>
            </div>

            <div className="form-group">
              <label className="form-label">Position</label>
              <select
                name="PositionID"
                className="form-control"
                value={formData.PositionID}
                onChange={handleChange}
              >
                <option value="">Select Position</option>
                {positions.map((pos) => (
                  <option key={pos.PositionID} value={pos.PositionID}>
                    {pos.PositionName}
                  </option>
                ))}
              </select>
            </div>
          </div>

          {/* Row 5: Status */}
          <div className="form-row">
            <div className="form-group">
              <label className="form-label">Status</label>
              <select
                name="Status"
                className="form-control"
                value={formData.Status}
                onChange={handleChange}
              >
                <option value="Active">Active</option>
                <option value="Inactive">Inactive</option>
                <option value="On Leave">On Leave</option>
                <option value="Terminated">Terminated</option>
              </select>
            </div>
            <div className="form-group"></div>
          </div>

          {/* Sync Checkbox */}
          <div className="form-group" style={{ marginTop: '20px' }}>
            <label style={{
              display: 'flex',
              alignItems: 'center',
              gap: '10px',
              cursor: 'pointer',
              padding: '12px',
              background: '#f0fff4',
              borderRadius: '8px',
              border: '1px solid #c6f6d5'
            }}>
              <input
                type="checkbox"
                checked={syncAfterSave}
                onChange={(e) => setSyncAfterSave(e.target.checked)}
                style={{ width: '18px', height: '18px' }}
              />
              <FaSync style={{ color: '#38a169' }} />
              <span style={{ color: '#276749', fontWeight: '500' }}>
                Sync to Payroll System after saving
              </span>
            </label>
          </div>

          {/* Buttons */}
          <div style={{
            display: 'flex',
            gap: '12px',
            marginTop: '24px',
            paddingTop: '24px',
            borderTop: '1px solid #e2e8f0'
          }}>
            <button type="submit" className="btn btn-success" disabled={saving}>
              <FaSave />
              {saving ? 'Saving...' : isEditMode ? 'Update Employee' : 'Create Employee'}
            </button>
            <button
              type="button"
              className="btn btn-secondary"
              onClick={() => navigate('/employees')}
              disabled={saving}
            >
              <FaTimes />
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default EmployeeForm;
